// src/components/UploadForm.js
import React, { useState } from "react";

export default function UploadForm({ setResult, setLoading }) {
  const [file, setFile] = useState(null);
  const [error, setError] = useState("");

  const onFileChange = (e) => {
    setFile(e.target.files[0]);
    setError("");
  };

  const onSubmit = async (e) => {
    e.preventDefault();
    if (!file) {
      setError("Please select an image first.");
      return;
    }

    const form = new FormData();
    form.append("image", file);

    try {
      setLoading(true);
      setResult(null);

      const resp = await fetch("http://127.0.0.1:5000/api/scan", {
        method: "POST",
        body: form
      });

      const data = await resp.json();
      if (!resp.ok) setError(data.error || "Something went wrong.");
      else setResult(data);

    } catch (err) {
      setError("Network error.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={onSubmit} style={{ marginBottom: "25px", textAlign: "center" }}>

      <input
        type="file"
        accept="image/*"
        onChange={onFileChange}
        style={{
          padding: "15px",
          width: "100%",
          border: "2px dashed #475569",
          borderRadius: "10px",
          background: "#f8fafc",
          cursor: "pointer"
        }}
      />

      <button
        type="submit"
        style={{
          marginTop: "18px",
          background: "#1e40af",
          color: "white",
          padding: "12px 35px",
          fontSize: "17px",
          borderRadius: "10px",
          border: "none",
          cursor: "pointer"
        }}
      >
        Scan Image
      </button>

      {error && <p style={{ color: "red", marginTop: "12px" }}>{error}</p>}
    </form>
  );
}
